import "../styles/Team.css";

export default function Team() {
  const teamMembers = [
    {
      name: "John Doe",
      role: "Lead Designer",
      imgSrc: "/path-to-image/john.jpg", // Replace with the actual path
      caption: "Creative and innovative design expert",
    },
    {
      name: "Jane Smith",
      role: "Senior Developer",
      imgSrc: "/path-to-image/jane.jpg", // Replace with the actual path
      caption: "Building the future of web development",
    },
    {
      name: "Emily Johnson",
      role: "Project Manager",
      imgSrc: "/path-to-image/emily.jpg", // Replace with the actual path
      caption: "Organizing projects with precision and passion",
    },
  ];

  return (
    <section className="team-section">
      <h3>Meet the Team</h3>
      <p>Our team consists of passionate designers and developers.</p>
      <div className="team-members">
        {teamMembers.map((member, index) => (
          <div key={index} className="team-member">
            <img src={member.imgSrc} alt={member.name} className="team-img" />
            <h4>{member.name}</h4>
            <p className="role">{member.role}</p>
            <p className="caption">{member.caption}</p>
          </div>
        ))}
      </div>
    </section>
  );
}
